import { useEffect, useState } from "react";
import {
  Container,
  Card,
  Button,
  Alert,
  Form,
  Spinner,
  Table,
  Badge,
  Row,
  Col,
} from "react-bootstrap";
import { useNavigate, useParams } from "react-router-dom";
import { getOrderDetail } from "../services/orderService";
import { createPaymentIntent, processPayment } from "../services/paymentService";

function PaymentPage() {
  const { orderId } = useParams();
  const navigate = useNavigate();

  const [order, setOrder] = useState(null);
  const [items, setItems] = useState([]);
  const [walletAddress, setWalletAddress] = useState("");
  const [paymentIntentId, setPaymentIntentId] = useState("");
  const [loading, setLoading] = useState(true);
  const [creatingIntent, setCreatingIntent] = useState(false);
  const [paying, setPaying] = useState(false);
  const [error, setError] = useState("");
  const [success, setSuccess] = useState("");

  const loadOrder = async () => {
    const response = await getOrderDetail(orderId);

    if (response.data?.success) {
      setOrder(response.data.data.order);
      setItems(response.data.data.items || []);

      if (
        response.data.data.order?.payment_status === "paid" &&
        response.data.data.order?.order_status === "confirmed"
      ) {
        setError("");
        setSuccess("Thanh toán và mint NFT thành công");
      }
    } else {
      setError("Không lấy được thông tin đơn hàng");
    }
  };

  useEffect(() => {
    const fetchOrder = async () => {
      try {
        setLoading(true);
        setError("");
        await loadOrder();
      } catch (err) {
        setError(err.response?.data?.message || "Lỗi khi tải đơn hàng");
      } finally {
        setLoading(false);
      }
    };

    fetchOrder();
  }, [orderId]);

  const handleCreateIntent = async () => {
    try {
      setCreatingIntent(true);
      setError("");
      setSuccess("");

      const response = await createPaymentIntent(orderId);

      if (response.data?.success) {
        setPaymentIntentId(response.data.data.paymentIntentId);
        setSuccess("Đã tạo yêu cầu thanh toán");
      } else {
        setError(response.data?.message || "Không tạo được thanh toán");
      }
    } catch (err) {
      setError(err.response?.data?.message || "Lỗi khi tạo payment intent");
    } finally {
      setCreatingIntent(false);
    }
  };

  const handleProcessPayment = async () => {
    try {
      if (!paymentIntentId) {
        setError("Bạn cần tạo yêu cầu thanh toán trước");
        return;
      }

      if (!walletAddress.trim()) {
        setError("Vui lòng nhập địa chỉ ví");
        return;
      }

      setPaying(true);
      setError("");
      setSuccess("");

      await processPayment({
        orderId,
        paymentIntentId,
        walletAddress,
      });

      await loadOrder();
    } catch (err) {
      try {
        await loadOrder();
      } catch {
        setError(err.response?.data?.message || "Lỗi khi xử lý thanh toán");
      }
    } finally {
      setPaying(false);
    }
  };

  const getPaymentBadge = (status) => {
    switch (status) {
      case "paid":
        return "success";
      case "failed":
        return "danger";
      case "refunded":
        return "secondary";
      default:
        return "warning";
    }
  };

  const getOrderBadge = (status) => {
    switch (status) {
      case "confirmed":
        return "success";
      case "cancelled":
        return "secondary";
      case "failed":
        return "danger";
      default:
        return "warning";
    }
  };

  if (loading) {
    return (
      <div className="d-flex justify-content-center align-items-center" style={{ minHeight: "70vh" }}>
        <Spinner animation="border" />
      </div>
    );
  }

  if (!order) {
    return (
      <Container className="user-shell text-center">
        <h3>Không tìm thấy đơn hàng</h3>
      </Container>
    );
  }

  const isPaid =
    order.payment_status === "paid" && order.order_status === "confirmed";

  return (
    <Container className="user-shell">
      <Row className="g-4">
        <Col lg={8}>
          <Card className="payment-card">
            <Card.Body className="p-4 p-lg-5">
              <div className="section-title mb-2">Thanh toán đơn hàng</div>
              <div className="section-subtitle mb-4">
                Hoàn tất thanh toán và nhận NFT ticket về ví của bạn.
              </div>

              {error && <Alert variant="danger">{error}</Alert>}
              {success && <Alert variant="success">{success}</Alert>}

              <Row className="g-3 mb-4">
                <Col md={6}>
                  <div className="payment-summary-box">
                    <div className="text-muted mb-1">Mã đơn</div>
                    <div className="fw-bold fs-5">{order.order_code}</div>
                  </div>
                </Col>
                <Col md={6}>
                  <div className="payment-summary-box">
                    <div className="text-muted mb-1">Tổng tiền</div>
                    <div className="fw-bold fs-5">
                      {Number(order.total_amount).toLocaleString("vi-VN")} VND
                    </div>
                  </div>
                </Col>
              </Row>

              <div className="d-flex gap-3 flex-wrap mb-4">
                <Badge bg={getPaymentBadge(order.payment_status)} className="status-badge">
                  Thanh toán: {order.payment_status}
                </Badge>
                <Badge bg={getOrderBadge(order.order_status)} className="status-badge">
                  Đơn hàng: {order.order_status}
                </Badge>
              </div>

              <h5 className="fw-bold mb-3">Chi tiết vé</h5>

              <Table responsive hover className="table-modern align-middle mb-4">
                <thead>
                  <tr>
                    <th>Loại vé</th>
                    <th>Số lượng</th>
                    <th>Đơn giá</th>
                    <th>Thành tiền</th>
                  </tr>
                </thead>
                <tbody>
                  {items.map((item) => (
                    <tr key={item.id}>
                      <td className="fw-semibold">{item.ticket_type_name}</td>
                      <td>{item.quantity}</td>
                      <td>{Number(item.unit_price).toLocaleString("vi-VN")} VND</td>
                      <td>{Number(item.subtotal).toLocaleString("vi-VN")} VND</td>
                    </tr>
                  ))}
                </tbody>
              </Table>

              {!isPaid && (
                <Form.Group className="mb-4">
                  <Form.Label>Địa chỉ ví nhận NFT</Form.Label>
                  <Form.Control
                    type="text"
                    placeholder="Nhập địa chỉ ví dạng 0x..."
                    value={walletAddress}
                    onChange={(e) => setWalletAddress(e.target.value)}
                  />
                </Form.Group>
              )}

              <div className="d-flex gap-3 flex-wrap">
                {!isPaid && (
                  <>
                    <Button
                      className="soft-button soft-button-outline"
                      onClick={handleCreateIntent}
                      disabled={creatingIntent}
                    >
                      {creatingIntent ? "Đang tạo..." : "Tạo yêu cầu thanh toán"}
                    </Button>

                    <Button
                      className="soft-button soft-button-primary"
                      onClick={handleProcessPayment}
                      disabled={paying}
                    >
                      {paying ? "Đang xử lý..." : "Thanh toán ngay"}
                    </Button>
                  </>
                )}

                <Button
                  className="soft-button soft-button-dark"
                  onClick={() => navigate("/profile")}
                >
                  Về hồ sơ
                </Button>
              </div>
            </Card.Body>
          </Card>
        </Col>

        <Col lg={4}>
          <Card className="payment-card">
            <Card.Body className="p-4">
              <div className="section-title mb-3" style={{ fontSize: "1.4rem" }}>
                Tiến trình
              </div>

              <div className="d-flex flex-column gap-3">
                <div className="payment-summary-box">
                  <div className="fw-bold">1. Tạo đơn hàng</div>
                  <div className="text-muted">Đã hoàn tất</div>
                </div>

                <div className="payment-summary-box">
                  <div className="fw-bold">2. Thanh toán</div>
                  <div className="text-muted">
                    {order.payment_status === "paid" ? "Đã hoàn tất" : "Chưa hoàn tất"}
                  </div>
                </div>

                <div className="payment-summary-box">
                  <div className="fw-bold">3. Mint NFT ticket</div>
                  <div className="text-muted">
                    {order.order_status === "confirmed" ? "Đã hoàn tất" : "Đang chờ xử lý"}
                  </div>
                </div>
              </div>
            </Card.Body>
          </Card>
        </Col>
      </Row>
    </Container>
  );
}

export default PaymentPage;
